import { defineStore } from 'pinia';
import { getFingerprint } from '@/utils/utils'
// import { generateImage, fetchResul } from '@/api/ai'
import * as ps from '@/utils/ps'
import { renderCanvas } from '@/utils/ps'
import * as SDProvider from '@/api/sd'


const aspectRatios = ["21:9", "16:9", "3:2", "5:4", "1:1", "4:5", "2:3", "9:16", "9:21"];
const findClosestAspectRatio = (width, height) => {
  const inputRatio = width / height;
  let closest = aspectRatios[0];
  let minDiff = Infinity;

  aspectRatios.forEach(ratioStr => {
    const [w, h] = ratioStr.split(":").map(Number);
    const ratio = w / h;
    const diff = Math.abs(inputRatio - ratio);

    if (diff < minDiff) {
      minDiff = diff;
      closest = ratioStr;
    }
  });

  return closest;
}



export const useWebUIStore = defineStore('webui', {
  persist: {
    key: 'ap-webui',
    storage: localStorage
  },
  state: () => {
    return {
      showLocalWebUi: false,
      showRemoteAI: false,
      fingerprint: null,
      loading: false,
      interrupt: false,
      currentCancel: null, // 添加新的状态来存储当前的cancel函数
      apiKey: "",
      model: "core",
      prompt: "",
      txt2img: {
        prompt: "",
        negative_prompt: ""
      },
      inpaint: {
        prompt: ""
      },
      outpaint: {
        prompt: "",
        up: 0,
        down: 0,
        left: 0,
        right: 0,
        creativity: 0.5,
      },
    }
  },
  getters: {
  },
  actions: {
    clickIcon(pluginName) {
      if (pluginName === 'WebUI') {
        this.showLocalWebUi = !this.showLocalWebUi
      }
      if (pluginName === 'RemoteAI') {
        this.showRemoteAI = !this.showRemoteAI
      }
      window.ps._j3.sr.vB[0].IF()
    },
    async txt2imgHandle() {
      let info = ps.getInfo()
      let aspect_ratio = findClosestAspectRatio(info.w, info.h)
      let buffer = await SDProvider.txt2img({ ...this.txt2img, apiKey: this.apiKey, aspect_ratio })
      ps.renderCanvasByBuffer(buffer)
    },
    // async upscale() {
    //   return await SDProvider.upscale()
    // },
    async inpaintHandle() {
      let mask = await ps.getSelectArea('blob')
      let image = await ps.getActiveCanvas('blob')
      let buffer = await SDProvider.inpaint({
        ...this.inpaint, image, mask, apiKey: this.apiKey
      })
      ps.renderCanvasByBuffer(buffer)
    },
    async outpaintHandle() {
      let image = await ps.getActiveCanvas('blob')
      let buffer = await SDProvider.outpaint({ ...this.outpaint, image, apiKey: this.apiKey })
      let info = ps.getInfo()
      let width = parseInt(this.outpaint.left) + parseInt(this.outpaint.right) + info.w
      let height = parseInt(this.outpaint.up) + parseInt(this.outpaint.down) + info.h
      // console.log("outpaintHandle", this.outpaint, width, height)
      ps.setCanvasSize(width, height)
      ps.setImageSize(width, height)
      // 等待图片渲染成功后
      setTimeout(() => {
        ps.renderCanvasByBuffer(buffer, width, height)
      }, 1000)
    },
    async eraseHandle() {
      let mask = await ps.getSelectArea('blob')
      let image = await ps.getActiveCanvas('blob')
      let buffer = await SDProvider.erase({
        image, mask, apiKey: this.apiKey
      })
      ps.renderCanvasByBuffer(buffer)
    },
    async cutoutHandle() {
      let image = await ps.getActiveCanvas('blob')
      let buffer = await SDProvider.removeBackground({
        image, apiKey: this.apiKey
      })
      ps.renderCanvasByBuffer(buffer)
    },
    doInterrupt() {
      this.interrupt = true
      if (this.currentCancel) {
        this.currentCancel() // 调用cancel函数来中断请求
      }
      this.interrupt = false
    },
    async generate(data) {
      this.loading = true
      this.interrupt = false
      if (!this.fingerprint) {
        this.fingerprint = await getFingerprint()
      }
      const { promise, cancel } = await generateImage(this.fingerprint, data);
      this.currentCancel = cancel; // 保存cancel函数

      return promise.then((res) => {
        this.currentCancel = null; // 清除cancel函数
        return res
      }).catch(error => {
        this.currentCancel = null; // 确保在出错时也清除cancel函数
        throw error;
      })
    },
    async fetchResultByTrack_id(track_id, type) {
      const { promise, cancel } = await fetchResul(this.fingerprint, { track_id: track_id, type: type });
      this.currentCancel = cancel; // 保存cancel函数
      return promise.then((res) => {
        if (res.message?.output) {
          renderCanvas(res.message.output)
          return
        } else if (!res.message.output) {
          throw new Error('No output image generated')
        }
        this.currentCancel = null; // 清除cancel函数
        return res
      }).catch(error => {
        this.currentCancel = null; // 确保在出错时也清除cancel函数
        throw error;
      })
    }
  },
});
