/**
* 使用 Stability Outpaint API 扩展图像边缘
* @param {Object} options
* @param {string} options.image - 输入图像
* @param {number} options.left - 向左扩展的像素数
* @param {number} options.down - 向下扩展的像素数
* @param {string} options.apiKey - API 密钥
* @returns {Promise<void>}
*/
export async function outpaint({ image, up, down, left, right, creativity, apiKey }) {
  console.log("outpaint", up, down, left, right)
  const formData = new FormData();
  formData.append("image", image, "image.png");
  formData.append("up", parseInt(up));
  formData.append("down", parseInt(down));
  formData.append("left", parseInt(left));
  formData.append("right", parseInt(right));
  formData.append("creativity", parseFloat(creativity).toFixed(2));
  formData.append("output_format", "webp");

  const response = await fetch("https://api.stability.ai/v2beta/stable-image/edit/outpaint", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      Accept: "image/*",
    },
    body: formData,
  });

  if (!response.ok) {
    const errorBuffer = await response.arrayBuffer();
    const errorText = new TextDecoder().decode(errorBuffer);
    throw new Error(`${response.status}: ${errorText}`);
  }
  const buffer = await response.arrayBuffer();
  return buffer
}



