/**
 * 功能：获得用户选区，矩形、椭圆、快速
 * 
 * @returns base64
 */
export function getSelectArea(type = 'base64') {
    // fN fN {x: 69, y: 244, r: 29, $: 27}
    let activebV = window.ps._j3.avd
    let bV = window.ps._j3.dU[activebV]

    if (!bV.d) return null
    const select = bV.d.w
    const originImg = bV.$0
    if (!select) return null

    const { x, y, r: width, $: height } = select

    // 创建与原始图片相同尺寸的 canvas
    let canvas = document.createElement('canvas');
    canvas.width = originImg.r;  // 使用原始图片宽度
    canvas.height = originImg.$; // 使用原始图片高度
    let ctx = canvas.getContext('2d');

    // 设置其他区域为透明
    ctx.fillStyle = 'black';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 只绘制选区区域, 矩形选择、椭圆选择、快速选择等
    const imageData = ctx.createImageData(width, height);
    let data = window.ps._j3.dU[0].d.O
    for (let i = 0; i < data.length; i++) {
        imageData.data[i * 4] = data[i] > 0 ? 255 : 0; // R
        imageData.data[i * 4 + 1] = data[i] > 0 ? 255 : 0; // G
        imageData.data[i * 4 + 2] = data[i] > 0 ? 255 : 0; // B
        imageData.data[i * 4 + 3] = 255; // A
    }
    ctx.putImageData(imageData, x, y);
    // ctx.fillStyle = 'white'; // 设置遮罩颜色为白色
    // ctx.fillRect(x, y, width, height);

    // 获取base64数据并移除前缀
    if (type === 'base64') {
        const base64Data = canvas.toDataURL('image/png').replace(/^data:image\/\w+;base64,/, '');
        return base64Data;
    } else {
        return new Promise((resolve) => {
            canvas.toBlob((blob) => {
                resolve(blob);
            }, 'image/png');
        });
    }
}


/**
 * 功能：获得当前激活图层的图片内容
 * 
 * @returns  base64
 */
export function getActiveCanvas(type = 'base64') {
    // fN fN {x: 69, y: 244, r: 29, $: 27}
    let activebV = window.ps._j3.avd
    let bV = window.ps._j3.dU[activebV]
    let activeLayer = bV.Y[0]
    let j4 = bV.U[activeLayer]

    // 创建 ImageData 对象
    const imageData = new ImageData(
        new Uint8ClampedArray(j4.buffer),
        j4.w.r,  // width
        j4.w.$   // height
    );

    // 创建临时 canvas
    const canvas = document.createElement('canvas');
    canvas.width = j4.w.r;
    canvas.height = j4.w.$;
    const ctx = canvas.getContext('2d');

    // 将 ImageData 绘制到 canvas
    ctx.putImageData(imageData, 0, 0);

    // 转换为 base64，并移除 data:image/png;base64, 前缀
    if (type === 'base64') {
        const base64Data = canvas.toDataURL('image/png').replace(/^data:image\/\w+;base64,/, '');
        return base64Data;
    } else {
        return new Promise((resolve) => {
            canvas.toBlob((blob) => {
                resolve(blob);
            }, 'image/png');
        });
    }
}




